import functools

def retry(times):
    def decorator(func):
        @functools.wraps(func)
        def wrapper(*args, **kwargs):
            for i in range(times):
                try:
                    return func(*args, **kwargs)
                except Exception:
                    if i == times - 1:
                        raise
        return wrapper
    return decorator

counter = 0

@retry(3)
def unstable():
    global counter
    counter += 1
    if counter < 3:
        raise ValueError
    return 'ok'

print(unstable())
print(counter)

