class Matrix:
    def __init__(self, data):
        self.data = data
    def __matmul__(self, other):
        result = []
        for i in range(len(self.data)):
            row = []
            for j in range(len(other.data[0])):
                s = sum(self.data[i][k] * other.data[k][j] for k in range(len(other.data)))
                row.append(s)
            result.append(row)
        return Matrix(result)

