import sys

class TracingMeta(type):
    def __new__(mcs, name, bases, namespace):
        cls = super().__new__(mcs, name, bases, namespace)
        for key, value in namespace.items():
            if callable(value) and not key.startswith('_'):
                setattr(cls, key, mcs.traced(value, name))
        return cls
    @staticmethod
    def traced(func, classname):
        def wrapper(*args, **kwargs):
            print(f'{classname}.{func.__name__}', end=' ')
            return func(*args, **kwargs)
        return wrapper

class Math(metaclass=TracingMeta):
    def add(self, a, b):
        return a + b

m = Math()
print(m.add(1, 2))
